public class CustomTokenServices extends TokenService {

    private List<GrantedAuthority> grantedAuthorityList = new ArrayList<>();
    private JwtEncoder jwtEncoder;

    public CustomTokenServices() {
        // Configure the list of GrantedAuthorities (role(s) that this token should be issued to).
        // In our case, we want to allow any client to request an access/refresh token.
        grantedAuthorityList = new ArrayList<>();
        grantedAuthorityList.add(new SimpleGrantedAuthority("ROLE_CLIENT"));

        jwtEncoder = JwtTokenUtil.getJwtTokenBuilder().build();
    }

    @Override
    protected OAuth2Authentication createOAuth2Authentication(ClientAuthentication clientAuth, TokenRequest tokenRequest) {
        // Return null because the AuthenticationManager should only handle authentication/authorization, and we don't want any authorities.
        return null;
    }
    
    public AccessTokenResponse createAccessToken(DefaultOAuth2AccessToken defaultOAuth2AccessToken, OAuth2Authentication authentication) {
        OAuth2AccessToken token = new DefaultOAuth2AccessToken(defaultOAuth2AccessToken);
        Map<String, Object> map = Maps.newHashMap();
        map.put("access_token", jwtEncoder.encode(token));
        map.putAll(authentication.getRefreshToken().getAdditionalInformation());
        return new AccessTokenResponse(map);
    }

    @Override
    public OAuth2Authentication loadAuthentication(String accessToken) {
        // No authentication is required for this token, because we have defined all necessary authorities in the constructor of this service class.

        Jwt jwt = jwtEncoder.decode(accessToken);
        
        Set<String> scopes = new HashSet<>();
        Set<SimpleGrantedAuthority> simpleGrantedAuthorities = new LinkedHashSet<>();
        Map<String, String> map = Maps.newHashMap();
        for (Map.Entry<String, Object> entry : jwt.getClaims().entrySet()) {
            if(entry.getKey() == "scope")
                scopes.add((String) entry.getValue());
            else { // All other key/value pairs will be in additional information of the token.
                map = (HashMap<String, String>) entry;
            }
        }

        for (String scope : scopes) 
            simpleGrantedAuthorities.add(new SimpleGrantedAuthority("ROLE_" + scope));
        
        // Set the user details and granted authorities.
        JwtUser jwtUser = new JwtUser();
        jwtUser.setUsername(map.get("user_name")); // Get the username from the claims of the token (as this is an internal service).
        jwtUser.setGrantedAuthorities(simpleGrantedAuthorities);

        return new OAuth2Authentication(new OAuth2AccessToken(map), jwtUser, simpleGrantedAuthorities);
    }
}


